function resolveIconUrl(name, customIcon, iconData, image="") {
  if (iconData)   return iconData;
  if (customIcon) return customIcon;
  // Search display name AND every segment of the full image path
  // e.g. "vaultwarden/server" → tries ["vaultwarden","server"] → finds vaultwarden ✓
  const norm = s => s.toLowerCase().replace(/[-_.]/g, "");
  const candidates = [...new Set([name, ...image.split("/")].map(norm).filter(s => s.length > 1))];
  for (const [k, v] of Object.entries(ICON_MAP)) {
    const key = norm(k);
    if (candidates.some(c => c.includes(key) || key.includes(c))) return `${ICON_CDN}/${v}.png`;
  }
  return null;
}

// ── Detection channel metadata ────────────────────────────────────────────────
// ── Tooltip component (floating chat bubble, 600ms delay, portal-based) ────────
function Tooltip({ text, children }) {
  const [visible, setVisible] = React.useState(false);
  const [pos, setPos] = React.useState({top:0, left:0});
  const timerRef = React.useRef(null);
  const anchorRef = React.useRef(null);

  const show = () => {
    if (anchorRef.current) {
      const r = anchorRef.current.getBoundingClientRect();
      setPos({ top: r.top + window.scrollY, left: r.left + r.width / 2 + window.scrollX });
    }
    setVisible(true);
  };

  return (
    <div ref={anchorRef} style={{position:"relative",display:"inline-flex"}}
      onMouseEnter={()=>{ timerRef.current = setTimeout(show, 600); }}
      onMouseLeave={()=>{ clearTimeout(timerRef.current); setVisible(false); }}>
      {children}
      {visible && createPortal(
        <div style={{
          position:"absolute",
          top: pos.top - 8,
          left: pos.left,
          transform:"translate(-50%, -100%)",
          background:"#1a1a2e",border:"1px solid #3a3a5c",borderRadius:8,
          padding:"7px 14px",fontSize:12,color:"#c8c8d8",lineHeight:1.5,
          whiteSpace:"normal",width:"max-content",maxWidth:400,zIndex:99999,
          boxShadow:"0 4px 18px rgba(0,0,0,.65)",pointerEvents:"none",
          textAlign:"center",
        }}>
          {text}
          <div style={{position:"absolute",top:"100%",left:"50%",transform:"translateX(-50%)",
            width:0,height:0,borderLeft:"6px solid transparent",borderRight:"6px solid transparent",
            borderTop:"6px solid #3a3a5c"}}/>
        </div>,
        document.body
      )}
    </div>
  );
}

// ── Timezone search select ────────────────────────────────────────────────────
function TzSelect({ value, onChange, inputStyle }) {
  const [query, setQuery] = React.useState("");
  const [open, setOpen] = React.useState(false);
  const ref = React.useRef(null);
  const filtered = React.useMemo(()=>
    TZ_OPTIONS.filter(o=> !query || o.label.toLowerCase().includes(query.toLowerCase()) || o.value.toLowerCase().includes(query.toLowerCase())),
  [query]);
  React.useEffect(()=>{
    if (!open) return;
    const h = e => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", h);
    return ()=>document.removeEventListener("mousedown", h);
  },[open]);
  const current = TZ_OPTIONS.find(o=>o.value===value) || {label:value,value};
  return (
    <div ref={ref} style={{position:"relative",flex:1,minWidth:200}}>
      <div onClick={()=>{setOpen(o=>!o);setQuery("");}}
        style={{...inputStyle,display:"flex",alignItems:"center",justifyContent:"space-between",cursor:"pointer",userSelect:"none"}}>
        <span style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flex:1}}>{current.label}</span>
        <span style={{marginLeft:6,opacity:.5,flexShrink:0}}>▾</span>
      </div>
      {open && (
        <div style={{position:"absolute",top:"calc(100% + 4px)",left:0,right:0,zIndex:9999,
          background:"#12121e",border:"1px solid #3a3a5c",borderRadius:8,
          boxShadow:"0 8px 32px rgba(0,0,0,.6)",overflow:"hidden"}}>
          <div style={{padding:"6px 8px",borderBottom:"1px solid #3a3a5c"}}>
            <input autoFocus placeholder="Search timezone…" value={query}
              onChange={e=>setQuery(e.target.value)}
              style={{width:"100%",background:"transparent",border:"none",outline:"none",
                color:"#e8e8f2",fontSize:12,padding:"2px 4px"}}/>
          </div>
          <div style={{maxHeight:220,overflowY:"auto"}}>
            {filtered.length===0
              ? <div style={{padding:"10px 12px",color:"#5a5a7a",fontSize:12}}>No results</div>
              : filtered.map(o=>(
                <div key={o.value}
                  onClick={()=>{onChange(o.value);setOpen(false);setQuery("");}}
                  style={{padding:"7px 12px",fontSize:12,cursor:"pointer",
                    background:o.value===value?"#A0A0B822":"transparent",
                    color:o.value===value?"#A0A0B8":"#c8c8d8",
                    transition:"background .12s"}}
                  onMouseEnter={e=>e.currentTarget.style.background="#ffffff0d"}
                  onMouseLeave={e=>e.currentTarget.style.background=o.value===value?"#A0A0B822":"transparent"}>
                  {o.label}
                </div>
              ))
            }
          </div>
        </div>
      )}
    </div>
  );
}

