// ── Accent Colour Picker (floating popup) ─────────────────────────────────────
// Converts HSV → RGB (all 0-1 range)
function hsvToRgb(h,s,v){
  const i=Math.floor(h*6), f=h*6-i, p=v*(1-s), q=v*(1-f*s), t=v*(1-(1-f)*s);
  const m=i%6;
  const [r,g,b]=m===0?[v,t,p]:m===1?[q,v,p]:m===2?[p,v,t]:m===3?[p,q,v]:m===4?[t,p,v]:[v,p,q];
  return [Math.round(r*255),Math.round(g*255),Math.round(b*255)];
}
// Converts RGB → HSV
function rgbToHsv(r,g,b){
  r/=255; g/=255; b/=255;
  const max=Math.max(r,g,b), min=Math.min(r,g,b), d=max-min;
  let h=0;
  if(d){
    if(max===r) h=((g-b)/d+6)%6;
    else if(max===g) h=(b-r)/d+2;
    else h=(r-g)/d+4;
    h/=6;
  }
  return [h, max?d/max:0, max];
}
function hexToRgb(hex){
  const h=hex.replace("#",""); const f=h.length===3?h.split("").map(c=>c+c).join(""):h;
  return [parseInt(f.slice(0,2),16),parseInt(f.slice(2,4),16),parseInt(f.slice(4,6),16)];
}
function rgbToHex(r,g,b){ return "#"+[r,g,b].map(x=>Math.round(x).toString(16).padStart(2,"0")).join(""); }

function AccentColorPicker({ value, onChange }) {
  // Parse incoming hex
  const [r0,g0,b0] = hexToRgb(value||"#A0A0B8");
  const [h0,s0,v0] = rgbToHsv(r0,g0,b0);

  const [open, setOpen]   = useState(false);
  const [hue,  setHue]    = useState(h0);
  const [sat,  setSat]    = useState(s0);
  const [val,  setVal]    = useState(v0);
  const [hexIn,setHexIn]  = useState((value||"#A0A0B8").replace("#","").toUpperCase());

  const popRef    = useRef(null);
  const svRef     = useRef(null);   // saturation/value canvas area
  const hueRef    = useRef(null);   // hue bar
  const svDragging  = useRef(false);
  const hueDragging = useRef(false);

  // Sync when value changes externally
  useEffect(()=>{
    const [rr,gg,bb]=hexToRgb(value||"#A0A0B8");
    const [hh,ss,vv]=rgbToHsv(rr,gg,bb);
    setHue(hh); setSat(ss); setVal(vv);
    setHexIn((value||"#A0A0B8").replace("#","").toUpperCase());
  },[value]);

  // Close on outside click
  useEffect(()=>{
    if(!open) return;
    const fn = e=>{ if(popRef.current && !popRef.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown",fn);
    return ()=>document.removeEventListener("mousedown",fn);
  },[open]);

  const commit = (h,s,v)=>{
    const [r,g,b]=hsvToRgb(h,s,v);
    const hex=rgbToHex(r,g,b);
    setHexIn(hex.replace("#","").toUpperCase());
    onChange(hex);
  };

  // ── SV pad drag ──
  const handleSvMove = useCallback((e)=>{
    if(!svDragging.current) return;
    const rect=svRef.current.getBoundingClientRect();
    const cx=e.touches?e.touches[0].clientX:e.clientX;
    const cy=e.touches?e.touches[0].clientY:e.clientY;
    const s=Math.max(0,Math.min(1,(cx-rect.left)/rect.width));
    const v=Math.max(0,Math.min(1,1-(cy-rect.top)/rect.height));
    setSat(s); setVal(v); commit(hue,s,v);
  },[hue]);

  const handleHueMove = useCallback((e)=>{
    if(!hueDragging.current) return;
    const rect=hueRef.current.getBoundingClientRect();
    const cx=e.touches?e.touches[0].clientX:e.clientX;
    const h=Math.max(0,Math.min(1,(cx-rect.left)/rect.width));
    setHue(h); commit(h,sat,val);
  },[sat,val]);

  useEffect(()=>{
    const up=()=>{ svDragging.current=false; hueDragging.current=false; };
    document.addEventListener("mouseup",up);
    document.addEventListener("touchend",up);
    document.addEventListener("mousemove",handleSvMove);
    document.addEventListener("touchmove",handleSvMove,{passive:false});
    document.addEventListener("mousemove",handleHueMove);
    document.addEventListener("touchmove",handleHueMove,{passive:false});
    return ()=>{
      document.removeEventListener("mouseup",up);
      document.removeEventListener("touchend",up);
      document.removeEventListener("mousemove",handleSvMove);
      document.removeEventListener("touchmove",handleSvMove);
      document.removeEventListener("mousemove",handleHueMove);
      document.removeEventListener("touchmove",handleHueMove);
    };
  },[handleSvMove,handleHueMove]);

  const [rH,gH,bH]=hsvToRgb(hue,1,1);
  const hueHex=rgbToHex(rH,gH,bH);
  const currentHex=rgbToHex(...hsvToRgb(hue,sat,val));

  // Dot position on SV pad
  const dotLeft=`${sat*100}%`;
  const dotTop=`${(1-val)*100}%`;
  // Marker on hue bar
  const hueLeft=`${hue*100}%`;

  const PRESETS=["#A0A0B8","#3c8ce0","#3ce08c","#e0c43c","#e05c5c","#b03ce0","#e03c8c","#3cd8e0","#e08c3c","#a0a0b8"];

  return (
    <div style={{position:"relative",display:"inline-block"}} ref={popRef}>
      {/* Trigger button */}
      <div onClick={()=>setOpen(o=>!o)} style={{
        width:40, height:40, borderRadius:10, background:value||"#A0A0B8",
        cursor:"pointer", border:"2px solid rgba(255,255,255,.15)",
        boxShadow:"0 2px 8px rgba(0,0,0,.4)",
        transition:"transform .12s, box-shadow .12s",
      }}/>

      {/* Popup */}
      {open && (
        <div style={{
          position:"absolute", top:"calc(100% + 10px)", left:0, zIndex:9999,
          background:"#1a1a2a", border:"1px solid #333352", borderRadius:14,
          padding:16, width:260, boxShadow:"0 12px 40px rgba(0,0,0,.7)",
          userSelect:"none",
        }}>
          {/* SV gradient pad */}
          <div ref={svRef}
            onMouseDown={e=>{ svDragging.current=true; handleSvMove(e); }}
            onTouchStart={e=>{ svDragging.current=true; handleSvMove(e); }}
            style={{
              position:"relative", width:"100%", height:150, borderRadius:8,
              background:`linear-gradient(to right, #fff, ${hueHex})`,
              cursor:"crosshair", marginBottom:12, overflow:"visible",
            }}>
            {/* black overlay top-to-bottom */}
            <div style={{position:"absolute",inset:0,borderRadius:8,
              background:"linear-gradient(to bottom, transparent, #000)",pointerEvents:"none"}}/>
            {/* white overlay right-to-left for saturation */}
            <div style={{position:"absolute",inset:0,borderRadius:8,
              background:"linear-gradient(to right, #fff, transparent)",pointerEvents:"none"}}/>
            {/* Cursor dot */}
            <div style={{
              position:"absolute", left:dotLeft, top:dotTop,
              transform:"translate(-50%,-50%)",
              width:14, height:14, borderRadius:"50%",
              border:"2px solid #fff", boxShadow:"0 0 0 1px rgba(0,0,0,.4)",
              background:currentHex, pointerEvents:"none",
            }}/>
          </div>

          {/* Hue bar */}
          <div ref={hueRef}
            onMouseDown={e=>{ hueDragging.current=true; handleHueMove(e); }}
            onTouchStart={e=>{ hueDragging.current=true; handleHueMove(e); }}
            style={{
              position:"relative", height:14, borderRadius:7, marginBottom:14,
              background:"linear-gradient(to right,#f00,#ff0,#0f0,#0ff,#00f,#f0f,#f00)",
              cursor:"pointer",
            }}>
            {/* Thumb */}
            <div style={{
              position:"absolute", left:hueLeft, top:"50%",
              transform:"translate(-50%,-50%)",
              width:18, height:18, borderRadius:"50%",
              background:hueHex, border:"2px solid #fff",
              boxShadow:"0 1px 4px rgba(0,0,0,.5)", pointerEvents:"none",
            }}/>
          </div>

          {/* Hex input row */}
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:12}}>
            <div style={{width:32,height:32,borderRadius:7,background:currentHex,
              border:"1px solid rgba(255,255,255,.15)",flexShrink:0}}/>
            <div style={{display:"flex",alignItems:"center",flex:1,
              background:"#0e0e1a",border:"1px solid #333352",borderRadius:8,
              padding:"0 10px",height:36}}>
              <span style={{color:"#5a5a7a",fontSize:13,marginRight:4}}>#</span>
              <input value={hexIn}
                onChange={e=>{
                  const raw=e.target.value.replace(/[^0-9a-fA-F]/g,"").slice(0,6).toUpperCase();
                  setHexIn(raw);
                  if(raw.length===6){
                    const [rr,gg,bb]=hexToRgb("#"+raw);
                    const [hh,ss,vv]=rgbToHsv(rr,gg,bb);
                    setHue(hh); setSat(ss); setVal(vv);
                    onChange("#"+raw);
                  }
                }}
                style={{background:"none",border:"none",outline:"none",
                  color:"#e8e8f2",fontFamily:"'Space Mono',monospace",
                  fontSize:13,width:"100%",letterSpacing:1}}
                maxLength={6} spellCheck={false}
                placeholder="6C63FF"
              />
            </div>
          </div>

          {/* Preset swatches */}
          <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
            {PRESETS.map(c=>{
              const sel=(value||"").toLowerCase()===c.toLowerCase();
              return (
                <div key={c} onClick={()=>{ onChange(c); setOpen(false); }}
                  title={c}
                  style={{
                    width:22,height:22,borderRadius:6,background:c,cursor:"pointer",
                    outline:sel?"2px solid #fff":"2px solid transparent",
                    outlineOffset:2,
                    boxShadow:sel?`0 0 0 4px ${c}55`:"0 1px 3px #0004",
                    transition:"outline .1s,box-shadow .1s",
                    flexShrink:0,
                  }}/>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

// ── Helpers ───────────────────────────────────────────────────────────────────
// Segments that are too generic to use as the app name
const GENERIC_SEGS = new Set(["server","app","backend","frontend","service","worker",
  "api","main","core","base","daemon","agent","proxy","client","web","container",
  "documentserver","community","ce","ee","oss","latest","stable","release",
  "official","public","open","hub","node","data","manager","controller"]);

function parseImage(raw) {
  const t=raw.trim(), ci=t.lastIndexOf(":"), si=t.lastIndexOf("/");
  const image   = ci>si&&ci!==-1 ? t.slice(0,ci) : t;
  const version = ci>si&&ci!==-1 ? t.slice(ci+1) : "latest";
  // Walk segments right-to-left; skip generic ones (e.g. "server" in joplin/server)
  const parts = image.split("/");
  let name = parts[parts.length-1];
  if (GENERIC_SEGS.has(name.toLowerCase()) && parts.length > 1) {
    // Try the preceding segment (the org/user, e.g. "joplin")
    name = parts[parts.length-2];
    // If that's a known registry host, fall back to the generic name
    if (name.includes(".")) name = parts[parts.length-1];
  }
  return { image, version, name };
}

const STATUS_COLORS = {"up-to-date":"#3ce08c",outdated:"#e05c5c",error:"#e08c3c",unknown:"#6b6b8a",pinned:"#a78bfa"};

// ── AppIcon ───────────────────────────────────────────────────────────────────
function AppIcon({ name, image="", customIcon, iconData, catColor, size=44, onClick, clickable=false }) {
  const [failed, setFailed] = useState(false);
  const url = resolveIconUrl(name, customIcon, iconData, image);
  const [hovered, setHovered] = useState(false);
  const base = { width:size, height:size, borderRadius:size*.27, flexShrink:0,
    cursor:clickable?"pointer":"default", position:"relative" };
  const overlay = clickable && hovered ? (
    <div style={{ position:"absolute",inset:0,background:"rgba(0,0,0,.5)",
      display:"flex",alignItems:"center",justifyContent:"center",
      borderRadius:size*.27,fontSize:size*.3,pointerEvents:"none" }}>📷</div>
  ) : null;
  const handlers = clickable ? {
    onMouseEnter:()=>setHovered(true), onMouseLeave:()=>setHovered(false), onClick,
  } : {};
  if (url && !failed) return (
    <div style={{...base,overflow:"hidden",background:catColor+"22",border:`1px solid ${catColor}33`,
      display:"flex",alignItems:"center",justifyContent:"center"}} {...handlers}>
      <img src={url} alt={name} onError={()=>setFailed(true)}
        style={{width:size*.72,height:size*.72,objectFit:"contain"}} draggable={false}/>
      {overlay}
    </div>
  );
  return (
    <div style={{...base,background:catColor+"33",border:`1px solid ${catColor}44`,
      display:"flex",alignItems:"center",justifyContent:"center",
      fontFamily:"'Space Mono',monospace",fontWeight:700,fontSize:size*.29,color:catColor}}
      {...handlers}>
      {name.slice(0,2).toUpperCase()}
      {overlay}
    </div>
  );
}

// ── ChannelPill ───────────────────────────────────────────────────────────────
function resolveChannelUrl(channel, image, versionSourceUrl) {
  // User-defined release notes URL always wins
  if (versionSourceUrl) return versionSourceUrl;
  if (!image || !channel) return null;
  // Strip tag and known registry prefixes that route through Docker Hub
  const _REGISTRY_PREFIXES = ["ghcr.io/", "lscr.io/", "registry.gitlab.com/", "quay.io/"];
  let img = image.split(":")[0]; // strip tag
  try {
    if (channel === "github") {
      // ghcr.io/owner/repo → strip registry prefix, use first two path segments
      const parts = img.replace("ghcr.io/", "").split("/");
      if (parts.length >= 2) return `https://github.com/${parts[0]}/${parts[1]}/releases`;
    }
    if (channel === "dockerhub") {
      // Strip registry host prefixes that proxy through Docker Hub
      // e.g. lscr.io/linuxserver/bookstack → linuxserver/bookstack
      let path = img;
      for (const prefix of _REGISTRY_PREFIXES) {
        if (path.startsWith(prefix)) { path = path.slice(prefix.length); break; }
      }
      const parts = path.split("/");
      if (parts.length === 1) return `https://hub.docker.com/_/${parts[0]}`;
      if (parts.length >= 2) return `https://hub.docker.com/r/${parts[0]}/${parts[1]}/tags`;
    }
    if (channel === "gitlab") {
      const parts = img.replace("registry.gitlab.com/", "").split("/");
      if (parts.length >= 2) return `https://gitlab.com/${parts[0]}/${parts[1]}/-/releases`;
    }
    if (channel === "gitea") {
      // e.g. codeberg.org/owner/repo or gitea.example.com/owner/repo
      const host = img.split("/")[0];
      const rest = img.split("/").slice(1);
      if (rest.length >= 2) return `https://${host}/${rest[0]}/${rest[1]}/releases`;
    }
    if (channel === "lscr") {
      // lscr.io/linuxserver/bookstack → https://fleet.linuxserver.io/ or hub.docker.com
      const path = img.replace("lscr.io/", "");
      const parts = path.split("/");
      if (parts.length >= 2) return `https://hub.docker.com/r/${parts[0]}/${parts[1]}/tags`;
    }
    if (channel === "quay") {
      const path = img.replace("quay.io/", "");
      return `https://quay.io/repository/${path}?tab=tags`;
    }
  } catch(_) {}
  return null;
}

function ChannelPill({ channel, url }) {
  const m = CHANNEL_META[channel] || CHANNEL_META.unknown;
  const neutralStyle = {
    display:"inline-flex",alignItems:"center",gap:4,fontSize:"9.5px",fontWeight:700,
    padding:"2px 8px",borderRadius:5,cursor:url?"pointer":"default",
    background:"transparent",
    color:"#5a5a7a",
    border:"0.5px solid rgba(255,255,255,0.12)",
    transition:"background .18s, color .18s, border-color .18s",
  };
  const inner = (
    <span title={url ? `Open ${m.label} page ↗` : m.desc}
      style={neutralStyle}
      onMouseEnter={e=>{
        e.currentTarget.style.background = m.color+"22";
        e.currentTarget.style.color = m.color;
        e.currentTarget.style.borderColor = m.color+"44";
      }}
      onMouseLeave={e=>{
        e.currentTarget.style.background = "transparent";
        e.currentTarget.style.color = "#5a5a7a";
        e.currentTarget.style.borderColor = "rgba(255,255,255,0.12)";
      }}
    >{m.icon} {m.label}</span>
  );
  if (url) return (
    <a href={url} target="_blank" rel="noopener noreferrer"
      style={{textDecoration:"none",display:"inline-flex"}}>
      {inner}
    </a>
  );
  return inner;
}

