// Strip near-black pixels from a base64 image (canvas-based, same logic as backend Pillow)
function stripBlackBackground(dataUrl, threshold=60) {
  return new Promise((resolve) => {
    if (!dataUrl || !dataUrl.startsWith("data:image/")) return resolve(dataUrl);
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement("canvas");
      canvas.width = img.width; canvas.height = img.height;
      const ctx = canvas.getContext("2d");
      ctx.drawImage(img, 0, 0);
      const d = ctx.getImageData(0, 0, canvas.width, canvas.height);
      for (let i = 0; i < d.data.length; i += 4) {
        const r = d.data[i], g = d.data[i+1], b = d.data[i+2];
        const sum = r + g + b;
        if (sum < threshold * 3) {
          d.data[i+3] = Math.min(255, Math.max(0, Math.round((sum - threshold) * 4)));
        }
      }
      ctx.putImageData(d, 0, 0);
      resolve(canvas.toDataURL("image/png"));
    };
    img.onerror = () => resolve(dataUrl);
    img.src = dataUrl;
  });
}

function _hexToRgba(hex, a) {
  const clean = (hex||"#A0A0B8").replace("#","");
  const full  = clean.length===3 ? clean.split("").map(c=>c+c).join("") : clean;
  const r = parseInt(full.slice(0,2),16), g = parseInt(full.slice(2,4),16), b = parseInt(full.slice(4,6),16);
  return `rgba(${r},${g},${b},${a})`;
}
function _contrastOn(hex) {
  const clean = (hex||"#A0A0B8").replace("#","");
  const full  = clean.length===3 ? clean.split("").map(c=>c+c).join("") : clean;
  const r = parseInt(full.slice(0,2),16)/255, g = parseInt(full.slice(2,4),16)/255, b = parseInt(full.slice(4,6),16)/255;
  const lum = 0.2126*r + 0.7152*g + 0.0722*b;
  return lum > 0.45 ? "#111" : "#fff";
}

