// FORCE CHANGE PASSWORD SCREEN
// ══════════════════════════════════════════════════════════════════════════════
function ChangePasswordScreen({ onDone }) {
  const [form, setForm]     = useState({ current:"", next:"", confirm:"" });
  const [error, setError]   = useState("");
  const [loading, setLoading] = useState(false);

  const submit = async e => {
    e.preventDefault(); setError("");
    if (form.next !== form.confirm) { setError("Passwords do not match."); return; }
    if (form.next.length < 8)       { setError("Minimum 8 characters."); return; }
    setLoading(true);
    try {
      const r = await fetch("/api/auth/change-password", {
        method:"POST", credentials:"include",
        headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ current_password:form.current, new_password:form.next }),
      });
      const data = await r.json();
      if (!r.ok) { setError(data.error||"Failed."); return; }
      onDone(data.user);
    } catch { setError("Network error."); }
    finally { setLoading(false); }
  };

  const fieldStyle = {
    width:"100%",background:"#0e0e1a",border:"1px solid #252538",borderRadius:9,
    padding:"11px 14px",fontFamily:"'Space Mono',monospace",fontSize:13,color:"#e8e8f2",outline:"none",
  };

  return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",
      background:"#08080f",fontFamily:"'Syne',sans-serif",padding:20}}>
      <div style={{width:"100%",maxWidth:420,background:"#10101c",border:"1px solid #e0c43c44",
        borderRadius:18,padding:36,animation:"su .25s ease"}}>
        <div style={{textAlign:"center",marginBottom:24}}>
          <div style={{fontSize:36,marginBottom:8}}>🔐</div>
          <div style={{fontFamily:"'Space Mono',monospace",fontWeight:700,fontSize:20,color:"#e0c43c"}}>Set a New Password</div>
          <div style={{fontSize:13,color:"#5a5a7a",marginTop:6,lineHeight:1.6}}>You're using the default password.<br/>Choose a new one to continue.</div>
        </div>
        <form onSubmit={submit}>
          {[["Current password","current","current-password"],
            ["New password (min 8 chars)","next","new-password"],
            ["Confirm new password","confirm","new-password"]].map(([label,key,ac])=>(
            <div key={key} style={{marginBottom:14}}>
              <label style={{display:"block",fontSize:11,fontWeight:700,textTransform:"uppercase",letterSpacing:".8px",color:"#5a5a7a",marginBottom:7}}>{label}</label>
              <input type="password" value={form[key]} autoComplete={ac} style={fieldStyle}
                onChange={e=>setForm(f=>({...f,[key]:e.target.value}))}/>
            </div>
          ))}
          {error&&<div style={{background:"#e05c5c18",border:"1px solid #e05c5c44",borderRadius:8,padding:"9px 12px",fontSize:13,color:"#e05c5c",marginBottom:14}}>{error}</div>}
          <button type="submit" disabled={loading||!form.current||!form.next||!form.confirm}
            style={{width:"100%",background:"#e0c43c",color:"#0a0a0a",border:"none",borderRadius:9,
              padding:"12px",fontFamily:"'Syne'",fontWeight:700,fontSize:14,cursor:"pointer",
              opacity:loading||!form.current||!form.next||!form.confirm?.5:1,transition:"opacity .18s"}}>
            {loading?"Saving…":"Set New Password"}
          </button>
        </form>
      </div>
    </div>
  );
}

