// ── Category keyword map (module-level — stable reference, no re-render issues) ──
const CAT_KEYWORDS = {
  media:       ["jellyfin","plex","emby","radarr","sonarr","bazarr","overseerr","tautulli","prowlarr","lidarr","readarr","jellyseerr"],
  music:       ["audiobookshelf","navidrome","beets","mopidy","funkwhale","spotify","subsonic"],
  productivity:["nextcloud","jenkins","portainer","gitea","jira","confluence","wiki","paperless","memos"],
  networking:  ["nginx","traefik","caddy","haproxy","pihole","wireguard","adguard","unbound","technitium","cloudflared"],
  monitoring:  ["grafana","prometheus","loki","influxdb","uptime","zabbix","netdata","checkmk","signoz","alertmanager"],
  database:    ["postgres","mysql","mariadb","mongo","redis","elastic","clickhouse","cassandra","sqlite"],
  storage:     ["minio","seafile","syncthing","filebrowser","immich","photoprism","duplicati","restic","backrest"],
  security:    ["vaultwarden","bitwarden","authelia","vault","keycloak","authentik","crowdsec","fail2ban"],
  development: ["gitlab","drone","woodpecker","n8n","nocodb","appwrite","forgejo","act_runner","gitea","code-server"],
};

function matchCategory(img, dbCats) {
  const l = img.toLowerCase();
  // DB categories first — user-defined keywords take priority
  for (const cat of (dbCats || [])) {
    if (cat.keywords.some(kw => kw && l.includes(kw.toLowerCase()))) return cat.key;
  }
  // Built-in keyword map fallback
  for (const [key, kws] of Object.entries(CAT_KEYWORDS)) {
    if (kws.some(kw => l.includes(kw))) return key;
  }
  return null;
}

